if r1@ == self_@ && r2@ == self_@ {
        assert(r1@ == r2@);
        match r1 {
            CSingleMessage::Message { seqno: s1, dst: d1, m: m1 } => {
                assert(r2 matches CSingleMessage::Message { .. });
                let s2 = r2.arrow_Message_seqno();
                let d2 = r2.arrow_Message_dst();
                let m2 = r2.arrow_Message_m();
                assert(s1 as nat == s2 as nat);
                assert(s1 == s2);
                assert(d1@ == d2@);
                assert(d1.id@ == d2.id@);
                assert(d1.id =~= d2.id);
                assert(d1 =~= d2);
                assert(m1@ == m2@);
                assert(m1 =~= m2);
                assert(r1 =~= r2);
            },
            CSingleMessage::Ack { ack_seqno: a1 } => {
                assert(r2 matches CSingleMessage::Ack { .. });
                let a2 = r2.arrow_Ack_ack_seqno();
                assert(a1 as nat == a2 as nat);
                assert(a1 == a2);
                assert(r1 =~= r2);
            },
            CSingleMessage::InvalidMessage {} => {
                assert(r2 matches CSingleMessage::InvalidMessage {});
                assert(r1 =~= r2);
            },
        }
        assert(r1 == r2);
    }
